    @unittest.expectedFailure
    def test_bug_005_installed_gate_retains_citation_verifier(self) -> None:
        """BUG-005: installed quality_gate.py should keep its Layer-1 verifier dependency."""
        with tempfile.TemporaryDirectory() as tmp:
            install_root = Path(tmp)
            gate_path = install_root / ".github" / "skills" / "quality_gate.py"
            gate_path.parent.mkdir(parents=True, exist_ok=True)
            shutil.copyfile(REPO_ROOT / ".github" / "skills" / "quality_gate" / "quality_gate.py", gate_path)
            probe = (
                "import importlib.util, pathlib, sys; "
                "path = pathlib.Path(sys.argv[1]); "
                "spec = importlib.util.spec_from_file_location('installed_quality_gate', path); "
                "mod = importlib.util.module_from_spec(spec); "
                "spec.loader.exec_module(mod); "
                "print('present' if mod._CITATION_VERIFIER is not None else 'missing')"
            )
            env = os.environ.copy()
            env["PYTHONPATH"] = str(install_root)
            result = subprocess.run(
                [sys.executable, "-c", probe, str(gate_path)],
                cwd=install_root,
                env=env,
                capture_output=True,
                text=True,
                check=True,
            )
            self.assertEqual(result.stdout.strip(), "present")

